payload.text:
Claro, voy a añadir una nueva pestaña "Biblioteca" (Library) a la barra lateral. Esta vista te permitirá ver todas las publicaciones registradas en la aplicación y filtrarlas por el testigo (Core) al que están asociadas, además de buscar por título o autor.

Aquí tienes los cambios necesarios:

1.  **`types.ts`**: Actualizar el tipo `SidebarView` para incluir la nueva vista.
2.  **`components/AllPublicationsView.tsx`**: Crear el nuevo componente que muestra la lista global y los filtros.
3.  **`App.tsx`**: Añadir el botón en la barra lateral y renderizar el nuevo componente.

Aquí está el código:

# Updated files:

## types.ts

```ts
import type { Dispatch, SetStateAction } from 'react';

export type DataPoint = {
  subsection?: string;
  // FIX: Added `| undefined` to the index signature to make it compatible with optional properties like `depth` and `age`, which could be undefined.
  [key: string]: string | number | boolean | null | undefined;
  depth?: number;
  age?: number;
  qcFlag?: 0 | 1 | 2; // 0: OK, 1: Suspect, 2: Exclude
};

export interface Taxonomy {
    kingdom: string;
    phylum: string;
    class: string;
    order: string;
    family: string;
    genus: string;
    species: string;
}

export interface EcologicalData {
    temperatureRange: string;
    depthHabitat: string;
    notes: string;
}

export interface Microfossil {
    id: string;
    taxonomy: Taxonomy;
    description: string;
    stratigraphicRange: string;
    ecology: EcologicalData;
    imageUrl: string;
}

export type PartialMicrofossil = Partial<Omit<Microfossil, 'taxonomy' | 'ecology'>> & {
  taxonomy?: Partial<Taxonomy>;
  ecology?: Partial<EcologicalData>;
};

export type FossilAbundance = 'Abundant' | 'Common' | 'Few' | 'Rare' | 'Barren' | 'Present';
export type FossilPreservation = 'Good' | 'Moderate' | 'Poor';

export interface SectionFossilRecord {
    fossilId: string;
    abundance: FossilAbundance;
    preservation: FossilPreservation;
    observations: string;
    count?: number;
    percentage?: number;
}

export interface LabAnalysis {
  delta18O?: number | null;
  delta13C?: number | null;
  mgCaRatio?: number | null;
  tex86?: number | null;
  alkenoneSST?: number | null;
  calculatedSST?: number | null;
  baCa?: number | null;
  srCa?: number | null;
  cdCa?: number | null;
  radiocarbonDate?: number | null;
}

export type CoreLocation = {
  lat: number;
  lon: number;
};

export interface PipelineStep {
    type: 'movingAverage';
    window: number;
}

export interface ProcessingPipeline {
    id: string;
    name: string;
    sourceProxy: string;
    steps: PipelineStep[];
}


// A Core is the main entity, representing a drilling site or expedition core.
export interface Core {
  id: string; // e.g., ODP-982A
  name: string; // e.g., Rockall Plateau Sediments
  location: CoreLocation;
  waterDepth: number; // in meters
  project: string;
  user_id?: string;
  folder_id?: string;
  createdAt?: string;
}

// A Section is a specific segment or hole within a Core, with its own data.
export interface Section {
  id:string; // Unique ID for the section (e.g., UUID)
  core_id: string; // Foreign key to the parent Core
  name: string; // e.g., "Hole A" or "Section 1H-1"
  sectionDepth: number; // Section Depth (m)
  sampleInterval?: number; // in m
  recoveryDate: string;
  collectionTime?: string; // e.g., 21:56
  epoch: string; // e.g., 'Pleistocene'
  geologicalPeriod: 'Glacial' | 'Interglacial' | 'Indeterminate';
  ageRange: string; // e.g., '0 - 1.2 Ma'
  dataPoints: DataPoint[];
  microfossilRecords: SectionFossilRecord[];
  labAnalysis?: LabAnalysis;
  summary?: string;
  sectionImage: string;
  collector?: string;
  lithology?: string;
  munsellColor?: string;
  grainSize?: string;
  tephraLayers?: string;
  paleomagneticReversals?: string;
  createdAt?: string;
  ageModel?: {
      tiePoints: TiePoint[];
  };
  pipelines?: ProcessingPipeline[];
}


export interface Folder {
    id: string;
    name: string;
    user_id: string;
    created_at: string;
}

export interface Source {
    uri: string;
    title: string;
}

export interface ChatMessage {
    role: 'user' | 'model';
    content: string;
    sources?: Source[];
}

export type SidebarView = 'list' | 'map' | 'imageAnalysis' | 'wiki' | 'publications';

export interface TiePoint {
    id: string;
    sectionId: string;
    depth: number;
    age: number;
}

export interface SpliceInterval {
    sectionId: string;
    startAge: number | null;
    endAge: number | null;
}

export interface NearbyCore {
    studyName: string;
    lat: number;
    lon: number;
    waterDepth: number | null;
    investigators: string;
    dataUrl: string;
}

// Type for sample data to be loaded for new users.
export type SampleSection = Omit<Section, 'id' | 'core_id' | 'createdAt'>;
export type SampleCore = Omit<Core, 'user_id' | 'folder_id' | 'createdAt'> & { sections: SampleSection[] };

// Type for user-defined custom proxies
export interface CustomProxy {
  key: string;
  label: string;
  unit: string;
}

export interface Publication {
  id: string; // UUID
  user_id: string;
  doi: string;
  title: string;
  authors: string;
  journal: string;
  year: number;
  abstract?: string;
  link?: string;
  created_at: string;
}

export interface CorePublicationLink {
    core_id: string;
    publication_id: string;
}


export interface CoreDashboardProps {
  core: Core;
  allCores: Core[];
  allSections: Section[];
  microfossils: Microfossil[];
  publications: Publication[];
  corePublicationLinks: CorePublicationLink[];
  onLinkCoreToPublication: (coreId: string, publicationId: string) => void;
  onUnlinkCoreFromPublication: (coreId: string, publicationId: string) => void;
  onOpenPublicationModal: (publication: Publication | null) => void;
  proxyLabels: Record<string, string>;
  commonDataKeys: Record<string, string[]>;
  onEditCore: (core: Core) => void;
  onDeleteCore: (coreId: string) => void;
  onGoToMap: () => void;
  setToast: (toast: { message: string; type: 'success' | 'error' | 'info'; show: boolean; }) => void;
  onAddFossil: (fossil: PartialMicrofossil) => void;
  userEmail: string;
  onOpenNearbyCores: (core: Core) => void;
  synthesisShortcutTrigger: number;
  onOpenCustomProxiesModal: () => void;
  onUpdateSectionData: (section: Section) => void;
  customProxies: CustomProxy[];
  compareSelection: string[];
  onClearCompare: () => void;
  onSelectForComparison: (coreId: string) => void;
  setConfirmModalState: Dispatch<SetStateAction<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
  }>>;
}

export type MapInteractionMode = 'pan' | 'draw-rect' | 'draw-poly';

export interface IdentifiedFossil {
    speciesName: string;
    confidenceScore: number;
    sourceImageUrl: string;
    analysis: {
        matchingFeatures: string[];
        distinguishingFeatures: string[];
    };
}

export interface FeedbackCorrection {
    incorrectSpecies: string;
    correctSpecies: string;
}

export interface ReinforcementFeedback {
    correctSpecies: string;
    image: {
        base64Data: string;
        mimeType: string;
    };
}

export interface PaleoEvent {
    eventName: string;
    startAge: number;
    endAge: number;
}

// Hook type for cross-component toast notifications
export type ToastType = {
    message: string;
    type: 'success' | 'error' | 'info';
    show: boolean;
};
export type useToastType = { addToast: (toast: Omit<ToastType, 'show'>) => void };
```

## components/AllPublicationsView.tsx

```tsx
import React, { useState, useMemo } from 'react';
import type { Publication, Core, CorePublicationLink } from '../types';
import { Search, ExternalLink, Filter, BookOpen, Edit, Trash2, MapPin } from 'lucide-react';

interface AllPublicationsViewProps {
    publications: Publication[];
    cores: Core[];
    corePublicationLinks: CorePublicationLink[];
    onEditPublication: (publication: Publication) => void;
    onDeletePublication: (publicationId: string) => void;
}

const AllPublicationsView: React.FC<AllPublicationsViewProps> = ({ 
    publications, 
    cores, 
    corePublicationLinks, 
    onEditPublication, 
    onDeletePublication 
}) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedCoreFilter, setSelectedCoreFilter] = useState<string>('all');

    const filteredPublications = useMemo(() => {
        let filtered = publications;

        // Filter by text search
        if (searchTerm) {
            const term = searchTerm.toLowerCase();
            filtered = filtered.filter(p =>
                p.title.toLowerCase().includes(term) ||
                p.authors.toLowerCase().includes(term) ||
                p.journal.toLowerCase().includes(term) ||
                String(p.year).includes(term)
            );
        }

        // Filter by Core
        if (selectedCoreFilter !== 'all') {
            const linkedPublicationIds = new Set(
                corePublicationLinks
                    .filter(link => link.core_id === selectedCoreFilter)
                    .map(link => link.publication_id)
            );
            filtered = filtered.filter(p => linkedPublicationIds.has(p.id));
        }

        return filtered;
    }, [publications, searchTerm, selectedCoreFilter, corePublicationLinks]);

    const getLinkedCoresForPub = (pubId: string) => {
        const coreIds = corePublicationLinks
            .filter(link => link.publication_id === pubId)
            .map(link => link.core_id);
        return cores.filter(c => coreIds.includes(c.id));
    };

    const selectClass = "bg-background-tertiary border border-border-secondary rounded-lg p-2 text-sm text-content-primary focus:ring-2 focus:ring-accent-primary focus:outline-none transition appearance-none bg-no-repeat bg-right pr-8";
    const selectIcon = `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='var(--text-muted)' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`;

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center flex-wrap gap-4">
                <h1 className="text-3xl font-bold text-content-primary flex items-center gap-3">
                    <BookOpen size={32} className="text-accent-primary"/> 
                    Research Library
                </h1>

                <div className="flex items-center gap-4 flex-grow md:flex-grow-0">
                    <div className="relative flex-grow md:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-content-muted" size={18} />
                        <input
                            type="text"
                            placeholder="Search title, author, year..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-background-tertiary border border-border-secondary rounded-lg py-2 pl-10 pr-4 text-content-primary placeholder-content-muted focus:ring-2 focus:ring-accent-primary focus:outline-none transition"
                        />
                    </div>

                    <div className="relative">
                        <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-content-muted" size={18} />
                        <select 
                            value={selectedCoreFilter} 
                            onChange={(e) => setSelectedCoreFilter(e.target.value)}
                            className={`${selectClass} pl-10`}
                            style={{ backgroundImage: selectIcon, backgroundPosition: 'right 0.5rem center', backgroundSize: '1.5em 1.5em' }}
                        >
                            <option value="all">All Cores</option>
                            {cores.map(core => (
                                <option key={core.id} value={core.id}>{core.id}</option>
                            ))}
                        </select>
                    </div>
                </div>
            </div>

            <div className="bg-background-tertiary/20 p-6 rounded-xl border border-border-primary/50 min-h-[70vh]">
                {filteredPublications.length > 0 ? (
                    <div className="grid grid-cols-1 gap-4">
                        {filteredPublications.map(pub => {
                            const linkedCores = getLinkedCoresForPub(pub.id);
                            return (
                                <div key={pub.id} className="bg-background-primary p-4 rounded-lg border border-border-secondary shadow-sm hover:border-accent-secondary/50 transition-all flex flex-col md:flex-row gap-4 justify-between animate-fade-in-fast">
                                    <div className="flex-grow space-y-2">
                                        <div>
                                            <h3 className="text-lg font-bold text-content-primary leading-snug">{pub.title}</h3>
                                            <p className="text-sm text-content-secondary">{pub.authors}</p>
                                            <p className="text-xs text-content-muted italic">{pub.journal}, {pub.year}</p>
                                        </div>

                                        <div className="flex items-center gap-4 text-xs">
                                            <span className="font-mono text-accent-secondary bg-accent-secondary/10 px-2 py-0.5 rounded">{pub.doi}</span>
                                            {pub.link && (
                                                <a href={pub.link} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-content-secondary hover:text-accent-primary transition-colors">
                                                    <ExternalLink size={12} /> View Source
                                                </a>
                                            )}
                                        </div>

                                        {linkedCores.length > 0 && (
                                            <div className="flex flex-wrap gap-2 pt-2">
                                                {linkedCores.map(core => (
                                                    <span key={core.id} className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-background-interactive text-xs font-medium text-content-secondary border border-border-secondary">
                                                        <MapPin size={10} />
                                                        {core.id}
                                                    </span>
                                                ))}
                                            </div>
                                        )}
                                    </div>

                                    <div className="flex flex-row md:flex-col gap-2 justify-end md:border-l md:border-border-secondary md:pl-4">
                                        <button 
                                            onClick={() => onEditPublication(pub)} 
                                            className="p-2 rounded-md text-content-muted hover:bg-background-interactive hover:text-content-primary transition-colors"
                                            title="Edit Details"
                                        >
                                            <Edit size={18} />
                                        </button>
                                        <button 
                                            onClick={() => onDeletePublication(pub.id)} 
                                            className="p-2 rounded-md text-content-muted hover:bg-danger-primary/20 hover:text-danger-primary transition-colors"
                                            title="Delete Publication"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center h-full py-20 text-content-muted">
                        <BookOpen size={48} className="mb-4 opacity-50" />
                        <h3 className="text-xl font-semibold">No publications found</h3>
                        <p className="text-sm">Try adjusting your search or filters.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default AllPublicationsView;
```

## App.tsx

```tsx
import React, { useState, useEffect, useMemo } from 'react';
// FIX: Added CustomProxy to the type import to resolve missing type definition.
import type { Core, Section, Microfossil, PartialMicrofossil, Folder, Publication, CorePublicationLink, SidebarView, ToastType, CustomProxy } from './types';
import CoreSelector from './components/CoreSelector';
import CoreDashboard from './components/CoreDashboard';
import AddCoreModal from './components/AddCoreModal';
import { BarChart3, Microscope, PlusCircle, LogOut, List, Map as MapIcon, Image, Info, Settings, Search, Edit, Trash2, GitCompare, Library } from 'lucide-react';
import Logo from './components/Logo';
import { supabase } from './services/supabaseClient';
import * as coreService from './services/coreService';
import { type Session } from '@supabase/supabase-js';
import AuthPage from './components/AuthPage';
import CoreMap from './components/CoreMap';
import { PROXY_LABELS, COMMON_DATA_KEYS, SAMPLE_DATA, FOSSIL_ASSOCIATED_PROXIES } from './constants';
import ImageAnalysisView from './components/ImageAnalysisView';
import MicropaleontologyTab from './components/MicropaleontologyTab';
import AccountModal from './components/AccountModal';
import ConfirmModal from './components/ConfirmModal';
import AddFossilModal from './components/AddFossilModal';
import Toast from './components/Toast';
import NearbyCoresModal from './components/NearbyCoresModal';
import ShortcutsModal from './components/ShortcutsModal';
import CustomProxiesModal from './components/CustomProxiesModal';
import CommandPalette from './components/CommandPalette';
import type { Command } from './components/CommandPalette';
import ExportWizard from './components/ExportWizard';
import { ToastProvider } from './components/useToast';
import AddPublicationModal from './components/AddPublicationModal';
import CoreComparisonView from './components/CoreComparisonView';
import AllPublicationsView from './components/AllPublicationsView';


const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [cores, setCores] = useState<Core[]>([]);
  const [allUserSections, setAllUserSections] = useState<Section[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [microfossils, setMicrofossils] = useState<Microfossil[]>([]);
  const [customProxies, setCustomProxies] = useState<CustomProxy[]>([]);
  const [publications, setPublications] = useState<Publication[]>([]);
  const [corePublicationLinks, setCorePublicationLinks] = useState<CorePublicationLink[]>([]);
  const [selectedCore, setSelectedCore] = useState<Core | null>(null);
  const [isCoreModalOpen, setIsCoreModalOpen] = useState(false);
  const [isAccountModalOpen, setIsAccountModalOpen] = useState(false);
  const [isShortcutsModalOpen, setIsShortcutsModalOpen] = useState(false);
  const [isCustomProxiesModalOpen, setIsCustomProxiesModalOpen] = useState(false);
  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
  const [isSavingProxies, setIsSavingProxies] = useState(false);
  const [editingCore, setEditingCore] = useState<Core | null>(null);
  const [sidebarView, setSidebarView] = useState<SidebarView>('list');
  const [isSidebarExpanded, setIsSidebarExpanded] = useState(false);
  const [initialDataLoaded, setInitialDataLoaded] = useState(false);
  const [synthesisShortcutTrigger, setSynthesisShortcutTrigger] = useState(0);

  const [isFossilModalOpen, setIsFossilModalOpen] = useState(false);
  const [fossilModalData, setFossilModalData] = useState<Microfossil | PartialMicrofossil | null>(null);

  const [isPublicationModalOpen, setIsPublicationModalOpen] = useState(false);
  const [editingPublication, setEditingPublication] = useState<Publication | null>(null);

  const [toast, setToast] = useState<ToastType | null>(null);

  const [confirmModalState, setConfirmModalState] = useState<{
      isOpen: boolean;
      title: string;
      message: string;
      onConfirm: () => void;
  }>({
      isOpen: false,
      title: '',
      message: '',
      onConfirm: () => {},
  });

  const [isNearbyCoresModalOpen, setIsNearbyCoresModalOpen] = useState(false);
  const [coreForNearbySearch, setCoreForNearbySearch] = useState<Core | null>(null);

  const [isExportWizardOpen, setIsExportWizardOpen] = useState(false);
  const [folderForExport, setFolderForExport] = useState<Folder | null>(null);

  const [compareSelection, setCompareSelection] = useState<string[]>([]);

  const addToast = (newToast: Omit<ToastType, 'show'>) => {
    setToast({ ...newToast, show: true });
  };

  useEffect(() => {
    if (selectedCore) {
        setCompareSelection([selectedCore.id]);
    }
  }, [selectedCore]);

  const fossilSpecificProxyLabels = useMemo(() => {
    const labels: Record<string, string> = {};
    microfossils.forEach(fossil => {
        const fossilName = `${fossil.taxonomy.genus.charAt(0)}. ${fossil.taxonomy.species}`;
        FOSSIL_ASSOCIATED_PROXIES.forEach(proxyKey => {
            if (PROXY_LABELS[proxyKey]) {
                const newKey = `${proxyKey}__${fossil.id}`;
                labels[newKey] = `${PROXY_LABELS[proxyKey]} (${fossilName})`;
            }
        });
    });
    return labels;
  }, [microfossils]);


  const mergedProxyLabels = useMemo(() => {
    const customLabels = Object.fromEntries(
        customProxies.map(p => [p.key, p.unit ? `${p.label} (${p.unit})` : p.label])
    );

    const fossilProxyLabels: Record<string, string> = {};
    microfossils.forEach(fossil => {
        const name = `${fossil.taxonomy.genus} ${fossil.taxonomy.species}`;
        fossilProxyLabels[`${fossil.id}_count`] = `${name} (Count)`;
        fossilProxyLabels[`${fossil.id}_percentage`] = `${name} (%)`;
    });

    return { ...PROXY_LABELS, ...fossilProxyLabels, ...customLabels, ...fossilSpecificProxyLabels };
  }, [customProxies, microfossils, fossilSpecificProxyLabels]);

  const mergedCommonDataKeys = useMemo(() => {
    const newKeys = { ...COMMON_DATA_KEYS };
    customProxies.forEach(p => {
        newKeys[p.key] = [p.key.toLowerCase(), p.label.toLowerCase()];
    });
    return newKeys;
  }, [customProxies]);

  const handleOpenNearbyCoresModal = (core: Core) => {
    setCoreForNearbySearch(core);
    setIsNearbyCoresModalOpen(true);
  };

  const handleSelectForComparison = (coreId: string) => {
      if (compareSelection[0]) {
          setCompareSelection([compareSelection[0], coreId]);
      }
  };

  const handleClearCompare = () => {
    if (compareSelection[0]) {
        setCompareSelection([compareSelection[0]]);
    }
  };

  const handleExportFolder = (folderId: string) => {
      const folder = folders.find(f => f.id === folderId);
      if (folder) {
          setFolderForExport(folder);
          setIsExportWizardOpen(true);
      }
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (_event === 'SIGNED_OUT') {
        // Reset state on logout
        setCores([]);
        setFolders([]);
        setAllUserSections([]);
        setPublications([]);
        setCorePublicationLinks([]);
        setSelectedCore(null);
        setInitialDataLoaded(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchData = async () => {
    if (!session?.user) return;
    try {
        const [coresAndFolders, fetchedSections, { microfossils: fetchedFossils }, publicationsAndLinks] = await Promise.all([
            coreService.fetchFoldersAndCores(session.user.id),
            coreService.fetchAllUserSections(session.user.id),
            coreService.fetchMicrofossils(),
            coreService.fetchPublicationsAndLinks(session.user.id),
        ]);
        const { cores: fetchedCores, folders: fetchedFolders } = coresAndFolders;
        const { publications: fetchedPubs, links: fetchedLinks } = publicationsAndLinks;

        const userCustomProxies = session.user.user_metadata?.custom_proxies || [];
        setCustomProxies(userCustomProxies);

        // Load sample data for new users
        if (fetchedCores.length === 0 && fetchedFolders.length === 0 && !initialDataLoaded) {
            setToast({ message: 'Welcome! Loading some sample data to get you started...', type: 'info', show: true });
            await coreService.loadSampleData(SAMPLE_DATA, session.user.id);
            // Re-fetch after loading sample data
            await fetchData();
            return;
        }

        setFolders(fetchedFolders);
        setCores(fetchedCores);
        setAllUserSections(fetchedSections);
        setMicrofossils(fetchedFossils);
        setPublications(fetchedPubs);
        setCorePublicationLinks(fetchedLinks);

        if (!selectedCore && fetchedCores.length > 0) {
            setSelectedCore(fetchedCores[0]);
        } else if (selectedCore) {
            // Ensure selected core is still valid
            const stillExists = fetchedCores.some(c => c.id === selectedCore.id);
            if (!stillExists) {
                setSelectedCore(fetchedCores[0] || null);
            }
        }

        setInitialDataLoaded(true);

    } catch (error: any) {
        setToast({ message: `Error fetching data: ${error.message}`, type: 'error', show: true });
    }
  };

  useEffect(() => {
    if (session?.user) {
      fetchData();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [session, initialDataLoaded]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
        const modKey = isMac ? e.metaKey : e.ctrlKey;
        const isInputFocused = e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement;

        if (modKey && e.key === 'k') {
            e.preventDefault();
            setIsCommandPaletteOpen(true);
        }
        if (e.key === 'f' && !isInputFocused) {
            e.preventDefault();
            setIsCommandPaletteOpen(true);
        }
        if (e.key === '?' && !isInputFocused) {
            e.preventDefault();
            setIsShortcutsModalOpen(true);
        }
        if (modKey && e.key === ',') {
            e.preventDefault();
            setIsAccountModalOpen(true);
        }

        // Global shortcuts (only when no modal is open and not typing)
        if (!isInputFocused && !isCoreModalOpen && !isAccountModalOpen && !isShortcutsModalOpen && !isCustomProxiesModalOpen && !isCommandPaletteOpen && !isPublicationModalOpen) {
             if (e.key >= '1' && e.key <= '5') {
                e.preventDefault();
                const views: SidebarView[] = ['list', 'map', 'imageAnalysis', 'wiki', 'publications'];
                setSidebarView(views[parseInt(e.key) - 1]);
            }
            if (modKey && e.key === 'n') {
                e.preventDefault();
                handleOpenCoreModal(null);
            }
            if (selectedCore) {
                 if (modKey && (e.key === 'Backspace' || e.key === 'Delete')) {
                    e.preventDefault();
                    handleDeleteCore(selectedCore.id);
                 }
                 if (e.key.toLowerCase() === 'e') {
                     e.preventDefault();
                     handleOpenCoreModal(selectedCore);
                 }
            }
            if (e.key.toLowerCase() === 's') {
                e.preventDefault();
                setSynthesisShortcutTrigger(prev => prev + 1);
            }
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCore, isCoreModalOpen, isAccountModalOpen, isShortcutsModalOpen, isCustomProxiesModalOpen, isCommandPaletteOpen, isPublicationModalOpen]);

