import type { DataPoint, TiePoint, Section } from '../types';

/**
 * Linear interpolation between two points
 */
export const lerp = (x: number, x0: number, x1: number, y0: number, y1: number): number => {
    return y0 + (x - x0) * (y1 - y0) / (x1 - x0);
};

/**
 * Simplified Cubic Spline Interpolation
 * Provides a smoother curve for isotopic data than linear interpolation.
 */
export const cubicSplineInterpolation = (points: { x: number, y: number }[], targetX: number): number => {
    if (points.length < 3) return 0; // Spline needs at least 3 points

    // Implementation of Natural Cubic Spline
    const n = points.length - 1;
    const h = new Array(n);
    for (let i = 0; i < n; i++) h[i] = points[i + 1].x - points[i].x;

    const alpha = new Array(n);
    for (let i = 1; i < n; i++) {
        alpha[i] = (3 / h[i]) * (points[i + 1].y - points[i].y) - (3 / h[i - 1]) * (points[i].y - points[i - 1].y);
    }

    const l = new Array(n + 1);
    const mu = new Array(n + 1);
    const z = new Array(n + 1);
    l[0] = 1; mu[0] = 0; z[0] = 0;

    for (let i = 1; i < n; i++) {
        l[i] = 2 * (points[i + 1].x - points[i - 1].x) - h[i - 1] * mu[i - 1];
        mu[i] = h[i] / l[i];
        z[i] = (alpha[i] - h[i - 1] * z[i - 1]) / l[i];
    }

    l[n] = 1; z[n] = 0;
    const c = new Array(n + 1);
    const b = new Array(n);
    const d = new Array(n);
    c[n] = 0;

    for (let j = n - 1; j >= 0; j--) {
        c[j] = z[j] - mu[j] * c[j + 1];
        b[j] = (points[j + 1].y - points[j].y) / h[j] - h[j] * (c[j + 1] + 2 * c[j]) / 3;
        d[j] = (c[j + 1] - c[j]) / (3 * h[j]);
    }

    // Find interval for targetX
    let idx = 0;
    for (let i = 0; i < n; i++) {
        if (targetX >= points[i].x && targetX <= points[i + 1].x) {
            idx = i;
            break;
        }
    }

    const dx = targetX - points[idx].x;
    return points[idx].y + b[idx] * dx + c[idx] * dx * dx + d[idx] * dx * dx * dx;
};

/**
 * Calculates Sedimentation Rates (cm/ka) from age-depth control points
 */
export const calculateSedimentationRates = (tiePoints: TiePoint[]): { depth: number; age: number; rate: number }[] => {
    const sorted = [...tiePoints].sort((a, b) => a.age - b.age);
    if (sorted.length < 2) return [];

    const rates = [];
    for (let i = 0; i < sorted.length - 1; i++) {
        const p1 = sorted[i];
        const p2 = sorted[i + 1];

        const deltaAge = p2.age - p1.age; // ka
        const deltaDepth = p2.depth - p1.depth; // mbsf (convert to cm)

        // Rate = cm / ka
        const rate = deltaAge !== 0 ? (deltaDepth * 100) / deltaAge : 0;

        rates.push({
            depth: (p1.depth + p2.depth) / 2, // Midpoint for plotting
            age: (p1.age + p2.age) / 2,
            rate: parseFloat(rate.toFixed(2))
        });
    }
    return rates;
};

/**
 * Resamples a data series to a constant interval
 */
export const resampleSeries = (
    data: DataPoint[], 
    key: string, 
    domainKey: 'depth' | 'age', 
    interval: number, 
    method: 'linear' | 'spline'
): DataPoint[] => {
    const sortedData = [...data]
        .filter(d => d[domainKey] != null && d[key] != null)
        .sort((a, b) => (a[domainKey] as number) - (b[domainKey] as number));

    if (sortedData.length < 2) return [];

    const points = sortedData.map(d => ({ x: d[domainKey] as number, y: d[key] as number }));
    const minX = points[0].x;
    const maxX = points[points.length - 1].x;

    const resampled: DataPoint[] = [];
    for (let x = minX; x <= maxX; x += interval) {
        const val = method === 'linear' 
            ? interpolateLinearSeries(points, x) 
            : cubicSplineInterpolation(points, x);

        resampled.push({
            [domainKey]: parseFloat(x.toFixed(4)),
            [key]: parseFloat(val.toFixed(6)),
            subsection: `Resampled_${x.toFixed(2)}`
        });
    }
    return resampled;
};

const interpolateLinearSeries = (points: {x: number, y: number}[], targetX: number): number => {
    const nextIdx = points.findIndex(p => p.x >= targetX);
    if (nextIdx === -1) return points[points.length -1].y;
    if (nextIdx === 0) return points[0].y;

    const p0 = points[nextIdx - 1];
    const p1 = points[nextIdx];
    return lerp(targetX, p0.x, p1.x, p0.y, p1.y);
};

import React, { useState, useEffect, useMemo } from 'react';
import type { Section, TiePoint, DataPoint } from '../types';
import { Layers, Trash2, MapPin, Calendar, Clock, Loader2, TrendingUp, Scissors, Activity, BarChart2 } from 'lucide-react';
import { calculateLinearAgeModel } from '../services/coreService';
import { calculateSedimentationRates, resampleSeries } from '../services/chronologyService';
import AgeDepthChart from './AgeDepthChart';
import AgeModelAssistant from './AgeModelAssistant';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Label, AreaChart, Area } from 'recharts';

interface ChronologyTabProps {
  sections: Section[];
  onCalibratedDataChange: (calibratedSections: Section[]) => void;
  setToast: (toast: { message: string; type: 'success' | 'error' | 'info'; show: boolean }) => void;
}

type ChronoSubView = 'points' | 'rates' | 'interpolation';

const ChronologyTab: React.FC<ChronologyTabProps> = ({ sections, onCalibratedDataChange, setToast }) => {
  const [subView, setSubView] = useState<ChronoSubView>('points');
  const [tiePoints, setTiePoints] = useState<TiePoint[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Interpolation State
  const [interpProxy, setInterpProxy] = useState('');
  const [interpMethod, setInterpMethod] = useState<'linear' | 'spline'>('linear');
  const [interpInterval, setInterpInterval] = useState(0.5);
  const [resampledData, setResampledData] = useState<DataPoint[]>([]);

  useEffect(() => {
    const allTiePoints = sections.flatMap(s => s.ageModel?.tiePoints || []);
    const uniqueTiePoints = Array.from(new Map(allTiePoints.map(item => [item.id, item])).values());
    setTiePoints(uniqueTiePoints.sort((a, b) => a.depth - b.depth));
  }, [sections]);

  const sedimentationRates = useMemo(() => calculateSedimentationRates(tiePoints), [tiePoints]);

  const availableProxies = useMemo(() => {
    const proxies = new Set<string>();
    sections.forEach(s => s.dataPoints.forEach(dp => {
        Object.keys(dp).forEach(k => { if(typeof dp[k] === 'number' && k !== 'depth' && k !== 'age') proxies.add(k); });
    }));
    return Array.from(proxies).sort();
  }, [sections]);

  const handleGenerateAgeModel = async () => {
    if (tiePoints.length < 2) {
      setToast({ message: 'At least two tie-points are required.', type: 'error', show: true });
      return;
    }
    setIsLoading(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 50));
      const result = calculateLinearAgeModel(sections, tiePoints);
      onCalibratedDataChange(result);
      setToast({ message: 'Age model updated!', type: 'success', show: true });
    } catch (err: any) {
      setToast({ message: `Error: ${err.message}`, type: 'error', show: true });
    } finally {
      setIsLoading(false);
    }
  };

  const handleResample = () => {
    if (!interpProxy) return;
    const allPoints = sections.flatMap(s => s.dataPoints);
    const result = resampleSeries(allPoints, interpProxy, 'age', interpInterval, interpMethod);
    setResampledData(result);
    setToast({ message: `Resampled series generated with ${result.length} points.`, type: 'info', show: true });
  };

  const TabBtn = ({ id, label, icon: Icon }: { id: ChronoSubView, label: string, icon: any }) => (
    <button
        onClick={() => setSubView(id)}
        className={`flex items-center gap-2 px-4 py-2 text-sm font-bold border-b-2 transition-all ${subView === id ? 'border-accent-primary text-accent-primary' : 'border-transparent text-content-muted hover:text-content-primary'}`}
    >
        <Icon size={16} /> {label}
    </button>
  );

  return (
    <div className="space-y-6">
        <div className="flex border-b border-border-primary mb-4 overflow-x-auto">
            <TabBtn id="points" label="Age-Depth Model" icon={Clock} />
            <TabBtn id="rates" label="Sedimentation Rates" icon={TrendingUp} />
            <TabBtn id="interpolation" label="Interpolation & Spectral" icon={Activity} />
        </div>

        {subView === 'points' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fade-in">
                <div className="lg:col-span-1 space-y-4">
                    <div className="p-4 bg-background-primary/30 rounded-xl border border-border-primary">
                        <h3 className="text-md font-bold text-content-primary mb-4 flex items-center gap-2"><Layers size={18}/> Active Tie-Points</h3>
                        <div className="space-y-2 max-h-64 overflow-y-auto pr-2">
                            {tiePoints.map(tp => (
                                <div key={tp.id} className="flex items-center justify-between bg-background-primary/50 p-2 rounded-md text-xs font-mono">
                                    <div className="flex gap-3">
                                        <span className="text-accent-secondary">{tp.depth}m</span>
                                        <span className="text-success-primary">{tp.age}ka</span>
                                    </div>
                                    <button onClick={() => setTiePoints(prev => prev.filter(p => p.id !== tp.id))} className="text-danger-primary p-1 hover:bg-danger-primary/10 rounded"><Trash2 size={12}/></button>
                                </div>
                            ))}
                        </div>
                        <div className="mt-4 pt-4 border-t border-border-primary">
                            <AgeModelAssistant sections={sections} tiePoints={tiePoints} onTiePointsChange={setTiePoints} />
                        </div>
                    </div>
                    <button onClick={handleGenerateAgeModel} disabled={isLoading} className="w-full py-3 bg-accent-primary text-white rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-accent-primary-hover disabled:opacity-50">
                        {isLoading ? <Loader2 className="animate-spin"/> : <TrendingUp size={20}/>}
                        Calculate Age Model
                    </button>
                </div>
                <div className="lg:col-span-2 bg-background-primary/30 p-6 rounded-xl border border-border-primary h-[500px]">
                    <AgeDepthChart tiePoints={tiePoints} sections={sections} />
                </div>
            </div>
        )}

        {subView === 'rates' && (
            <div className="bg-background-primary/30 p-6 rounded-xl border border-border-primary h-[500px] animate-fade-in">
                <h3 className="text-lg font-bold text-content-primary mb-4 flex items-center gap-2"><TrendingUp size={20}/> Sedimentation Rate ($cm/ka$)</h3>
                <ResponsiveContainer width="100%" height="90%">
                    <AreaChart data={sedimentationRates} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                        <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                        <XAxis dataKey="age" tick={{fill: '#94a3b8'}} label={{ value: 'Age (ka)', position: 'insideBottom', offset: -5, fill: '#94a3b8' }} />
                        <YAxis tick={{fill: '#94a3b8'}} label={{ value: 'cm/ka', angle: -90, position: 'insideLeft', fill: '#94a3b8' }} />
                        <Tooltip contentStyle={{backgroundColor: '#1e293b', border: 'none', borderRadius: '8px'}} />
                        <Area type="stepAfter" dataKey="rate" stroke="#0ea5e9" fill="#0ea5e9" fillOpacity={0.3} name="Sedimentation Rate" />
                    </AreaChart>
                </ResponsiveContainer>
            </div>
        )}

        {subView === 'interpolation' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fade-in">
                <div className="lg:col-span-1 p-4 bg-background-primary/30 rounded-xl border border-border-primary space-y-4">
                    <h3 className="text-md font-bold text-content-primary">Standardization & Resampling</h3>
                    <div>
                        <label className="text-xs text-content-muted uppercase font-bold">Proxy</label>
                        <select value={interpProxy} onChange={e => setInterpProxy(e.target.value)} className="w-full bg-background-interactive p-2 rounded-md text-sm mt-1 border border-border-secondary">
                            <option value="">Select proxy...</option>
                            {availableProxies.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="text-xs text-content-muted uppercase font-bold">Method</label>
                            <select value={interpMethod} onChange={e => setInterpMethod(e.target.value as any)} className="w-full bg-background-interactive p-2 rounded-md text-sm mt-1 border border-border-secondary">
                                <option value="linear">Linear</option>
                                <option value="spline">Cubic Spline</option>
                            </select>
                        </div>
                        <div>
                            <label className="text-xs text-content-muted uppercase font-bold">Interval (ka)</label>
                            <input type="number" step="0.1" value={interpInterval} onChange={e => setInterpInterval(parseFloat(e.target.value))} className="w-full bg-background-interactive p-2 rounded-md text-sm mt-1 border border-border-secondary" />
                        </div>
                    </div>
                    <button onClick={handleResample} disabled={!interpProxy} className="w-full py-2 bg-accent-secondary text-white rounded-md font-bold hover:bg-accent-secondary-hover transition-colors">
                        Generate Resampled Series
                    </button>
                </div>
                <div className="lg:col-span-2 bg-background-primary/30 p-6 rounded-xl border border-border-primary h-[500px]">
                    <h3 className="text-md font-bold text-content-primary mb-4 flex items-center gap-2"><Activity size={18}/> Interpolated Curve</h3>
                    {resampledData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="90%">
                            <LineChart data={resampledData}>
                                <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                                <XAxis dataKey="age" tick={{fill: '#94a3b8'}} reversed />
                                <YAxis tick={{fill: '#94a3b8'}} reversed={interpProxy.includes('delta18O')} />
                                <Tooltip contentStyle={{backgroundColor: '#1e293b', border: 'none'}} />
                                <Line type="monotone" dataKey={interpProxy} stroke="#38bdf8" strokeWidth={2} dot={false} />
                            </LineChart>
                        </ResponsiveContainer>
                    ) : (
                        <div className="h-full flex items-center justify-center text-content-muted border-2 border-dashed border-border-primary rounded-lg">
                            Configure resampling parameters to visualize the interpolated series.
                        </div>
                    )}
                </div>
            </div>
        )}
    </div>
  );
};

