                point[yKey] = dp[yKey];
                point[zKey] = dp[zKey];
                return point;
            }).filter(p => p[xKey] != null && p[yKey] != null && p[zKey] != null);
        }

        const mergedData = new Map<any, any>();
        const xKey = xAxis.key;
        section.dataPoints.forEach(point => {
            const xValue = point[xKey];
            if (xValue != null) {
                let entry: Record<string, any> = mergedData.get(xValue) || { [xKey]: xValue };
