        });
        return Array.from(proxies).sort();
    }, [section]);

    const calibratedData = useMemo(() => applyAgeModel(section.dataPoints, tiePoints), [section.dataPoints, tiePoints]);
    const sedRates = useMemo(() => calculateSedRates(tiePoints), [tiePoints]);

