                    {/* REFERENCE PANEL (TOP) */}
                    <div className="bg-background-tertiary/20 p-4 rounded-xl border border-border-primary relative h-[250px]">
                        <div className="absolute top-2 left-4 z-10 flex items-center gap-2">
                            <span className="text-[10px] font-bold uppercase bg-background-interactive px-2 py-0.5 rounded text-content-muted">Reference: LR04 Benthic Stack</span>
                            {pickingMode === 'age' && <span className="text-[10px] font-bold uppercase bg-accent-secondary px-2 py-0.5 rounded text-white animate-pulse">Now pick corresponding age</span>}
