                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" />
                                <XAxis dataKey="age" hide reversed />
                                <YAxis hide domain={['auto', 'auto']} reversed />
                                <Tooltip contentStyle={{backgroundColor: '#0f172a', border: 'none', borderRadius: '8px', fontSize: '10px'}} />
                                <Line type="monotone" dataKey="d18O" stroke="#38bdf8" strokeWidth={2} dot={false} isAnimationActive={false} />
