                    {/* TARGET PANEL (BOTTOM) */}
                    <div className="bg-background-tertiary/20 p-4 rounded-xl border border-border-primary relative h-[350px]">
                        <div className="absolute top-2 left-4 z-10 flex items-center gap-2">
                            <span className="text-[10px] font-bold uppercase bg-background-interactive px-2 py-0.5 rounded text-content-muted">Record: {section.name}</span>
                            {pickingMode === 'depth' && <span className="text-[10px] font-bold uppercase bg-accent-primary px-2 py-0.5 rounded text-white animate-pulse">Pick Depth point</span>}
                        </div>
                        <ResponsiveContainer width="100%" height="100%">
                            <LineChart data={calibratedData} onClick={(d) => handleChartClick(d, 'depth')} style={{ cursor: pickingMode === 'depth' ? 'crosshair' : 'default' }}>
                                <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                                <XAxis 
                                    dataKey={viewMode === 'depth' ? 'depth' : 'age'} 
                                    reversed={viewMode === 'age'}
                                    tick={{fill: '#94a3b8', fontSize: 10}}
                                    label={{ value: viewMode === 'depth' ? 'Depth (mbsf)' : 'Calibrated Age (ka)', position: 'insideBottom', offset: -5, fill: '#94a3b8', fontSize: 12 }}
                                />
                                <YAxis tick={{fill: '#94a3b8', fontSize: 10}} domain={['auto', 'auto']} reversed={activeProxy.includes('delta18O')} />
                                <Tooltip contentStyle={{backgroundColor: '#0f172a', border: 'none', borderRadius: '8px', fontSize: '10px'}} />
                                <Line type="monotone" dataKey={activeProxy} stroke="#fb923c" strokeWidth={2} dot={false} isAnimationActive={false} />
                                {tiePoints.map(tp => (
                                    <ReferenceLine 
                                        key={tp.id} 
                                        x={viewMode === 'depth' ? tp.depth : tp.age} 
                                        stroke="#ef4444" 
                                        label={{ value: tp.age.toFixed(1), position: 'top', fill: '#ef4444', fontSize: 9 }}
