                    </div>
                </div>

                {/* Sidebar Diagnostics */}
                <div className="space-y-4">
                    <div className="bg-background-primary/40 p-4 rounded-xl border border-border-primary">
                        <h4 className="text-xs font-bold uppercase text-content-muted mb-3 flex items-center gap-2"><TrendingUp size={14}/> Tie-Points List</h4>
                        <div className="space-y-2 max-h-[300px] overflow-y-auto pr-2">
                            {tiePoints.length === 0 ? (
                                <p className="text-[10px] text-content-muted italic">No points picked. Enter Picking Mode to correlate.</p>
                            ) : tiePoints.map((tp, idx) => (
                                <div key={tp.id} className="group flex items-center justify-between bg-background-interactive/20 p-2 rounded border border-border-secondary">
                                    <div className="text-[10px] font-mono">
                                        <div className="text-accent-primary">Z: {tp.depth}m</div>
                                        <div className="text-success-primary">T: {tp.age}ka</div>
                                    </div>
                                    <button onClick={() => removeTiePoint(tp.id)} className="opacity-0 group-hover:opacity-100 text-danger-primary transition-opacity"><Trash2 size={12}/></button>
                                </div>
                            ))}
