                    </div>

                    <div className="bg-background-primary/40 p-4 rounded-xl border border-border-primary">
                        <h4 className="text-xs font-bold uppercase text-content-muted mb-3 flex items-center gap-2"><TrendingUp size={14}/> Sed. Rates</h4>
                        <div className="h-32 w-full">
                            {sedRates.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <ScatterChart margin={{top: 5, right: 5, left: -20, bottom: 0}}>
                                        <XAxis dataKey="age" hide />
                                        <YAxis tick={{fontSize: 8}} />
                                        <Tooltip />
                                        <Scatter data={sedRates} fill="#0ea5e9" line />
                                    </ScatterChart>
                                </ResponsiveContainer>
                            ) : (
                                <div className="h-full flex items-center justify-center text-[10px] text-content-muted italic text-center">Requires 2+ tie-points</div>
                            )}
                        </div>
                        <p className="text-[9px] text-content-muted mt-2">Current avg rate: <span className="text-accent-secondary font-bold">{sedRates.length > 0 ? (sedRates.reduce((a,b)=>a+b.rate, 0)/sedRates.length).toFixed(1) : '0'} cm/ka</span></p>
                    </div>

                    <div className="p-3 bg-accent-secondary/10 rounded-lg border border-accent-secondary/30">
                        <p className="text-[10px] text-accent-secondary leading-relaxed flex gap-2">
                            <Info size={14} className="flex-shrink-0" />
                            <strong>Pro-tip:</strong> En AnalySeries, el picking visual es la forma más rápida de detectar hiatos sedimentarios.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

