                        className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-black transition-all shadow-lg ${pickingMode !== 'none' ? 'bg-danger-primary text-white scale-105 ring-4 ring-danger-primary/20' : 'bg-accent-primary text-white hover:bg-accent-primary-hover hover:scale-105'}`}
                    >
