                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
                                <XAxis dataKey="age" hide reversed />
                                <YAxis hide domain={['auto', 'auto']} reversed />
                                <Tooltip 
                                    contentStyle={{backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '12px', color: '#22d3ee'}} 
                                    labelFormatter={(val) => `Age: ${val} ka`}
                                />
                                <Line 
                                    type="monotone" 
