                    <div className={`bg-background-secondary p-5 rounded-3xl border-2 transition-all h-[380px] relative shadow-inner ${pickingMode === 'depth' ? 'border-accent-primary ring-4 ring-accent-primary/20 scale-[1.02]' : 'border-border-primary'}`}>
